    """Parse a syslog-style log line. Returns dict with level/message/timestamp, or None."""
    m = SYSLOG_RE.match(line.strip())
    if not m:
        return None
    return {
        "timestamp": m.group("timestamp"),
        "level": m.group("level"),
        "message": m.group("message"),
    }


